# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

import requests

# RabbitMQ Management API endpoint
api_endpoint = "http://localhost:15672/api/"

# Virtual host configurations
vhosts = {
    "app1": {"users": ["user1", "user2"], "permissions": ["manage", "write", "read"]},
    "app2": {"users": ["user3", "user4"], "permissions": ["write", "read"]},
}

# Create virtual hosts
for vhost, config in vhosts.items():
    url = f"{api_endpoint}vhosts/{vhost}"
    response = requests.put(url)
    response.raise_for_status()

# Create users and grant permissions
for vhost, config in vhosts.items():
    for user in config["users"]:
        url = f"{api_endpoint}users/{user}"
        response = requests.put(url, json={"password": "password"})
        response.raise_for_status()

        for permission in config["permissions"]:
            url = f"{api_endpoint}permissions/{user}/{vhost}/{permission}"
            response = requests.put(url, json={"configure": True, "write": True, "read": True})
            response.raise_for_status()